/**
 * 图片优化器 - 用于增强图片加载和处理
 */
document.addEventListener('DOMContentLoaded', function() {
  // 检测浏览器支持的图片格式
  const webpSupport = localStorage.getItem('webpSupport') === 'true';
  const avifSupport = localStorage.getItem('avifSupport') === 'true';
  
  // 为所有内容图片添加优化
  const contentImages = document.querySelectorAll('.post-content img');
  contentImages.forEach(img => {
    // 添加错误处理
    img.addEventListener('error', function() {
      // 如果图片加载失败，尝试回退到原始格式
      const originalSrc = this.getAttribute('data-original-src') || this.src;
      if (this.src !== originalSrc) {
        this.src = originalSrc;
      }
      // 添加错误类
      this.classList.add('img-load-error');
    });
    
    // 添加点击放大功能
    img.addEventListener('click', function() {
      const overlay = document.createElement('div');
      overlay.className = 'img-overlay';
      overlay.style.position = 'fixed';
      overlay.style.top = '0';
      overlay.style.left = '0';
      overlay.style.width = '100%';
      overlay.style.height = '100%';
      overlay.style.backgroundColor = 'rgba(0,0,0,0.9)';
      overlay.style.display = 'flex';
      overlay.style.alignItems = 'center';
      overlay.style.justifyContent = 'center';
      overlay.style.zIndex = '9999';
      
      const imgClone = document.createElement('img');
      imgClone.src = this.src;
      imgClone.style.maxWidth = '90%';
      imgClone.style.maxHeight = '90%';
      imgClone.style.objectFit = 'contain';
      
      overlay.appendChild(imgClone);
      document.body.appendChild(overlay);
      
      overlay.addEventListener('click', function() {
        this.remove();
      });
    });
  });
  
  // 添加图片加载完成事件
  const allImages = document.querySelectorAll('img[loading="lazy"]');
  allImages.forEach(img => {
    // 保存原始尺寸
    if (img.width && img.height) {
      img.setAttribute('data-original-width', img.width);
      img.setAttribute('data-original-height', img.height);
    }
    
    // 添加加载完成类
    img.addEventListener('load', function() {
      this.classList.add('img-loaded');
    });
  });
  
  // 性能监控和报告
  if ('performance' in window && 'PerformanceObserver' in window) {
    // 收集性能指标
    let performanceMetrics = {
      lcp: 0,  // Largest Contentful Paint
      fid: 0,  // First Input Delay
      cls: 0,  // Cumulative Layout Shift
      loadTime: 0 // 页面加载时间
    };
    
    // 记录页面加载时间
    window.addEventListener('load', function() {
      if (performance.timing) {
        performanceMetrics.loadTime = 
          performance.timing.loadEventEnd - performance.timing.navigationStart;
        
        // 如果加载时间过长，可以在控制台输出警告
        if (performanceMetrics.loadTime > 3000) {
          console.warn('页面加载时间过长:', performanceMetrics.loadTime + 'ms');
        }
      }
    });
  }
});